import json
import anthropic
from typing import Any
from enum import Enum

# Cricket-themed data structures for agentic workflow
class CricketToolName(str, Enum):
    FETCH_PLAYER_STATS = "fetch_player_stats"
    GET_MATCH_HISTORY = "get_match_history"
    CALCULATE_AVERAGE = "calculate_average"
    CHECK_INJURY_STATUS = "check_injury_status"

class CricketAgent:
    """Agentic workflow agent managing cricket player analysis tasks."""

    def __init__(self, model: str = "claude-3-5-sonnet-20241022"):
        self.client = anthropic.Anthropic()
        self.model = model
        self.tools = self._define_cricket_tools()
        self.state = {"iteration_count": 0, "tool_calls": [], "task_complete": False}

    def _define_cricket_tools(self) -> list[dict]:
        """Define available tools for the agent."""
        return [
            {
                "name": "fetch_player_stats",
                "description": "Retrieve batting/bowling statistics for a cricket player",
                "input_schema": {
                    "type": "object",
                    "properties": {
                        "player_name": {
                            "type": "string",
                            "description": "Full name of the cricket player (e.g., 'Rohit Sharma')"
                        },
                        "stat_type": {
                            "type": "string",
                            "enum": ["batting", "bowling"],
                            "description": "Type of statistics to fetch"
                        }
                    },
                    "required": ["player_name", "stat_type"]
                }
            },
            {
                "name": "get_match_history",
                "description": "Retrieve recent match history for a player",
                "input_schema": {
                    "type": "object",
                    "properties": {
                        "player_name": {
                            "type": "string",
                            "description": "Player name to fetch history for"
                        },
                        "last_n_matches": {
                            "type": "integer",
                            "description": "Number of recent matches to retrieve (default: 5)",
                            "default": 5
                        }
                    },
                    "required": ["player_name"]
                }
            },
            {
                "name": "calculate_average",
                "description": "Calculate batting or bowling average from a list of scores",
                "input_schema": {
                    "type": "object",
                    "properties": {
                        "scores": {
                            "type": "array",
                            "items": {"type": "number"},
                            "description": "List of runs/wickets to calculate average from"
                        },
                        "calc_type": {
                            "type": "string",
                            "enum": ["batting_average", "bowling_average"],
                            "description": "Type of average to calculate"
                        }
                    },
                    "required": ["scores", "calc_type"]
                }
            },
            {
                "name": "check_injury_status",
                "description": "Check current injury/availability status of a player",
                "input_schema": {
                    "type": "object",
                    "properties": {
                        "player_name": {
                            "type": "string",
                            "description": "Name of player to check"
                        }
                    },
                    "required": ["player_name"]
                }
            }
        ]

    def _execute_tool(self, tool_name: str, tool_input: dict) -> Any:
        """Simulate tool execution with realistic cricket data."""
        # Simulated database responses
        player_stats = {
            "Rohit Sharma": {"batting": {"runs": 8000, "matches": 150, "average": 53.3, "centuries": 25}},
            "Jasprit Bumrah": {"bowling": {"wickets": 156, "matches": 100, "economy": 4.5, "average": 22.3}},
            "Virat Kohli": {"batting": {"runs": 12000, "matches": 190, "average": 63.2, "centuries": 48}}
        }

        match_histories = {
            "Rohit Sharma": [45, 62, 18, 91, 33],
            "Jasprit Bumrah": [2, 1, 3, 2, 2],  # Wickets taken
        }

        injury_status = {
            "Rohit Sharma": "Fit",
            "Jasprit Bumrah": "Minor hamstring concern, available",
            "Virat Kohli": "Fit"
        }

        if tool_name == "fetch_player_stats":
            player = tool_input.get("player_name")
            stat_type = tool_input.get("stat_type")
            if player in player_stats:
                return {"status": "success", "data": player_stats[player].get(stat_type, {})}
            return {"status": "error", "message": f"Player {player} not found in database"}

        elif tool_name == "get_match_history":
            player = tool_input.get("player_name")
            last_n = tool_input.get("last_n_matches", 5)
            if player in match_histories:
                return {"status": "success", "matches": match_histories[player][-last_n:]}
            return {"status": "error", "message": f"No match history for {player}"}

        elif tool_name == "calculate_average":
            scores = tool_input.get("scores", [])
            calc_type = tool_input.get("calc_type")
            if not scores:
                return {"status": "error", "message": "No scores provided"}
            avg = sum(scores) / len(scores)
            return {"status": "success", "average": round(avg, 2), "type": calc_type}

        elif tool_name == "check_injury_status":
            player = tool_input.get("player_name")
            if player in injury_status:
                return {"status": "success", "player": player, "status": injury_status[player]}
            return {"status": "error", "message": f"Unknown player {player}"}

        return {"status": "error", "message": f"Unknown tool {tool_name}"}

    def run_agentic_loop(self, user_task: str, max_iterations: int = 10) -> str:
        """Execute the agentic reasoning loop."""
        messages = [{"role": "user", "content": user_task}]

        for iteration in range(max_iterations):
            self.state["iteration_count"] = iteration + 1

            # Agent calls LLM to reason and decide next action
            response = self.client.messages.create(
                model=self.model,
                max_tokens=1024,
                tools=self.tools,
                messages=messages
            )

            # Check if task is complete (agent returned final answer)
            if response.stop_reason == "end_turn":
                # Extract final text response
                for block in response.content:
                    if hasattr(block, "text"):
                        self.state["task_complete"] = True
                        return block.text

            # Process tool use if present
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    tool_name = block.name
                    tool_input = block.input

                    # Execute tool and capture result
                    tool_result = self._execute_tool(tool_name, tool_input)
                    self.state["tool_calls"].append({
                        "tool": tool_name,
                        "input": tool_input,
                        "result": tool_result
                    })

                    # Add to conversation for next iteration
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": json.dumps(tool_result)
                    })

            # Update messages for next iteration
            messages.append({"role": "assistant", "content": response.content})
            if tool_results:
                messages.append({"role": "user", "content": tool_results})
            else:
                # No tools were called; agent should provide final answer
                for block in response.content:
                    if hasattr(block, "text"):
                        self.state["task_complete"] = True
                        return block.text

        return "Max iterations reached without task completion"


# Main execution
if __name__ == "__main__":
    agent = CricketAgent()

    # Task: Analyze a player's performance
    task = """Analyze Rohit Sharma's recent performance. 
    1. Get his last 5 match scores
    2. Calculate his batting average from those scores
    3. Check his current injury status
    4. Based on this data, provide a brief performance assessment."""

    print("=== Cricket Agent Analysis ===")
    print(f"Task: {task}")
    print("\n--- Agent Execution ---")

    result = agent.run_agentic_loop(task, max_iterations=10)

    print(f"\nFinal Result:\n{result}")
    print(f"\nAgent State:")
    print(f"  Iterations: {agent.state['iteration_count']}")
    print(f"  Task Complete: {agent.state['task_complete']}")
    print(f"  Tool Calls Made: {len(agent.state['tool_calls'])}")
    for i, call in enumerate(agent.state["tool_calls"], 1):
        print(f"    {i}. {call['tool']} → {call['result']['status']}")

# ❌ ANTI-PATTERN: Agent without reflection or validation
class CricketMatchAgent:
    def plan_innings(self, team_batting_stats, opposition_bowling):
        strategy = self.llm.generate(f"Plan an innings against {opposition_bowling}")
        return strategy  # No verification agent followed through

# ✅ BEST PRACTICE: Agentic Loop with Reflection
class CricketMatchAgent:
    def plan_innings(self, team_batting_stats, opposition_bowling):
        max_iterations = 3
        strategy = None

        for iteration in range(max_iterations):
            # Generate initial strategy
            strategy = self.llm.generate(
                f"Plan innings vs {opposition_bowling}, previous feedback: {strategy}"
            )

            # Reflection: Validate against constraints
            validation = self.validator.check(strategy, [
                f"batting_lineup_available",
                f"match_format_rules",
                f"opposition_bowling_analysis"
            ])

            if validation['is_valid']:
                strategy['confidence_score'] = validation['confidence']
                return strategy

            # If invalid, use feedback for next iteration
            strategy = validation['feedback_for_refinement']

        return strategy  # Return best attempt after reflection cycles

# Tool-First Design: Define tools before agent logic
CRICKET_TOOLS = {
    'get_batting_stats': lambda player: {...},
    'get_bowling_analysis': lambda bowler: {...},
    'check_pitch_conditions': lambda venue: {...}
}

class ToolFirstAgent:
    def __init__(self, available_tools):
        self.tools = available_tools  # All tools pre-validated

    def execute(self, task):
        # Agent can only call pre-defined, auditable tools
        for tool_name in self.extract_tool_calls(task):
            if tool_name not in self.tools:
                raise ValueError(f"Tool {tool_name} not in approved set")
            result = self.tools[tool_name]()
        return result
